@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Models

<div class="channel-list">
    <div class="channel-list-header">
        <h5>Channels</h5>
    </div>
    <ul class="channel-items">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <span class="channel-description">@TruncateDescription(channel.Description)</span>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }
}

@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Models

<div class="message-bubble @(IsThreadStarter ? "thread-starter" : "")"
     @onmouseenter="() => showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    <span>@reaction.Emoji</span>
                    <span class="reaction-count">@reaction.Users.Count</span>
                </button>
            }
        </div>
    }

    @if (IsThreadStarter && ReplyCount > 0)
    {
        <button class="thread-replies-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions && ShowActions)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
                💬 Reply
            </button>
            <button class="action-btn" title="Add reaction" @onclick="ToggleEmojiPicker">
                😀 React
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool IsThreadStarter { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool ShowActions { get; set; } = true;
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private void OnMouseLeave()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Models

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h4># @Channel.Name</h4>
            <p class="channel-desc">@Channel.Description</p>
        </div>

        <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
