@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Models

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h4># @Channel.Name</h4>
            <p class="channel-desc">@Channel.Description</p>
        </div>

        <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages...</div>
            }
            @foreach (var message in Messages)
            {
                var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == message.Id);
                <MessageBubble Message="message"
                               IsThreadStarter="@(summary is not null)"
                               ReplyCount="@(summary?.ReplyCount ?? 0)"
                               OnOpenThread="OnOpenThread"
                               OnReact="OnReact" />
            }
        </div>

        <div class="message-input-area">
            <textarea class="message-input" rows="2"
                      placeholder="Message #@Channel.Name"
                      @bind="newMessageContent"
                      @onkeydown="HandleKeyDown" />
            <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(newMessageContent)"
                    @onclick="SendMessage">
                Send
            </button>
        </div>
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private string newMessageContent = string.Empty;
    private ElementReference messageListRef;

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers load-more (handled via JS interop in production;
        // here we expose the callback for the parent to wire up)
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(newMessageContent)) return;
        var content = newMessageContent;
        newMessageContent = string.Empty;
        await OnSendMessage.InvokeAsync(content);
    }
}

