@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Models

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-thread-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <MessageBubble Message="RootMessage" ShowActions="false" />
        </div>

        <hr class="thread-divider" />

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <p class="no-replies">No replies yet. Start the conversation!</p>
            }
            @foreach (var reply in Replies)
            {
                <MessageBubble Message="reply"
                               ShowActions="false"
                               OnReact="OnReact" />
            }
        </div>

        <div class="thread-input-area">
            <textarea class="thread-input" rows="2"
                      placeholder="Reply..."
                      @bind="replyContent"
                      @onkeydown="HandleKeyDown" />
            <button class="reply-btn" disabled="@string.IsNullOrWhiteSpace(replyContent)"
                    @onclick="SendReply">
                Reply
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private string replyContent = string.Empty;

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(replyContent)) return;
        var content = replyContent;
        replyContent = string.Empty;
        await OnSendReply.InvokeAsync(content);
    }
}

