@page "/chat"
@rendermode InteractiveServer
@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Models
@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Services
@using sv_ed5e6b68715144d8a76f9dad705aa3f8.Components.Chat
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelList Channels="channels"
                     ActiveChannelId="activeChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(threadRootMessage is null ? "chat-main-full" : "")">
        <MessageArea Channel="activeChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     OnLoadMore="LoadMoreMessages"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage" />
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private List<Message> threadReplies = [];

    private Channel? activeChannel;
    private int? activeChannelId;
    private Message? threadRootMessage;
    private bool isLoadingMore;

    private const int PageSize = 30;
    private IJSObjectReference? jsModule;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadRootMessage = null;
        threadReplies = [];
        threadSummaries = [];

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channelId);

        // Update the channel's unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }

        await BuildThreadSummaries();
        StateHasChanged();

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", ".message-list");
        }
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || activeChannelId is null) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId.Value, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            await BuildThreadSummaries();
        }

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessage(string content)
    {
        if (activeChannelId is null) return;

        var message = await ChatService.SendMessageAsync(activeChannelId.Value, content, null);
        messages.Add(message);
        StateHasChanged();

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", ".message-list");
        }
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
        StateHasChanged();
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
        StateHasChanged();
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary
        await BuildThreadSummaries();
        StateHasChanged();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh the affected message in the list
        if (activeChannelId is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(activeChannelId.Value, 0, messages.Count);
            if (refreshed.Count > 0)
            {
                messages = refreshed;
            }
        }

        // Refresh thread if open
        if (threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
            threadRootMessage = messages.FirstOrDefault(m => m.Id == threadRootMessage.Id) ?? threadRootMessage;
        }

        StateHasChanged();
    }

    private async Task BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var summaries = new List<ThreadSummary>();
        foreach (var rootId in rootIds)
        {
            var thread = await ChatService.GetThreadAsync(rootId);
            if (thread.Count > 0)
            {
                summaries.Add(new ThreadSummary(
                    rootId,
                    thread.Count,
                    thread.Max(t => t.SentAt)));
            }
        }

        threadSummaries = summaries;
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            await jsModule.DisposeAsync();
        }
    }
}

export function scrollToBottom(selector) {
    const el = document.querySelector(selector);
    if (el) {
        el.scrollTop = el.scrollHeight;
    }
}

export function observeScrollTop(selector, dotNetRef) {
    const el = document.querySelector(selector);
    if (!el) return;
    el.addEventListener('scroll', () => {
        if (el.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    });
}

/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

