.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.channel-list-header {
    padding: 16px;
    border-bottom: 1px solid #202225;
}

.channel-list-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.channel-items {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #36393f;
}

.channel-item.active {
    background: #404348;
    color: #fff;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.75rem;
    color: #8e9297;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ===== Main Message Area ===== */
.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    transition: width 0.2s ease;
}

.chat-main-full {
    width: 80%;
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #202225;
    background: #36393f;
}

.message-area-header h4 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
}

.message-area-header .channel-desc {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #8e9297;
    font-size: 0.85rem;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #8e9297;
    font-size: 1.1rem;
}

/* ===== Message Bubble ===== */
.message-bubble {
    padding: 6px 12px;
    border-radius: 4px;
    position: relative;
    transition: background 0.1s;
}

.message-bubble:hover {
    background: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.7rem;
    color: #72767d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.4;
    word-wrap: break-word;
}

/* Reactions */
.reaction-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 2px 6px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #dcddde;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #4f545c;
}

.reaction-count {
    font-size: 0.75rem;
}

/* Thread replies link */
.thread-replies-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 2px;
    font-weight: 600;
}

.thread-replies-link:hover {
    text-decoration: underline;
}

