.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 4px;
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 0.75rem;
    padding: 4px 8px;
    border-radius: 3px;
    cursor: pointer;
    white-space: nowrap;
}

.action-btn:hover {
    background: #4f545c;
    color: #fff;
}

