.message-input-area, .thread-input-area {
    padding: 12px 20px;
    border-top: 1px solid #202225;
    display: flex;
    gap: 8px;
    align-items: flex-end;
    background: #36393f;
}

.message-input, .thread-input {
    flex: 1;
    background: #40444b;
    border: none;
    border-radius: 8px;
    color: #dcddde;
    padding: 10px 14px;
    font-size: 0.9rem;
    resize: none;
    outline: none;
    font-family: inherit;
}

.message-input:focus, .thread-input:focus {
    box-shadow: 0 0 0 2px #5865f2;
}

.send-btn, .reply-btn {
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.send-btn:hover, .reply-btn:hover {
    background: #4752c4;
}

.send-btn:disabled, .reply-btn:disabled {
    background: #4f545c;
    cursor: not-allowed;
}

/* ===== Thread Panel ===== */
.chat-thread {
    width: 25%;
    min-width: 280px;
    border-left: 1px solid #202225;
    background: #36393f;
    color: #dcddde;
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

.thread-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
}

.close-thread-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-thread-btn:hover {
    background: #4f545c;
    color: #fff;
}

.thread-root-message {
    padding: 12px 16px;
    background: #2f3136;
}

.thread-divider {
    border: none;
    border-top: 1px solid #4f545c;
    margin: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.no-replies {
    color: #8e9297;
    font-size: 0.85rem;
    text-align: center;
    padding: 20px;
}

.thread-input-area {
    background: #2f3136;
}

