/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ===== Sidebar ===== */
.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.channel-list-header {
    padding: 16px;
    border-bottom: 1px solid #202225;
}

.channel-list-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.channel-items {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #36393f;
}

.channel-item.active {
    background: #404348;
    color: #fff;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.75rem;
    color: #8e9297;
    display: block;
    margin-top: 2px;
